@namespace Lumeo

@{
    var context = new MenubarContext(_openMenuId, EventCallback.Factory.Create<string?>(this, SetOpenMenuId), _openMenuId is not null, _menuIds, RegisterMenuId, NavigateMenus);
}

<CascadingValue Value="context" IsFixed="false">
    <div role="menubar" class="@CssClass" @attributes="AdditionalAttributes">
        @ChildContent
    </div>
</CascadingValue>

@code {
    [Parameter] public RenderFragment? ChildContent { get; set; }
    [Parameter] public string? Class { get; set; }
    [Parameter(CaptureUnmatchedValues = true)] public Dictionary<string, object>? AdditionalAttributes { get; set; }

    private string? _openMenuId;
    private readonly List<string> _menuIds = [];

    private string CssClass => Cx.Merge("flex h-9 items-center space-x-1 rounded-md border border-border/40 bg-background p-1 shadow-sm", Class);

    private void SetOpenMenuId(string? menuId)
    {
        _openMenuId = menuId;
        StateHasChanged();
    }

    private void RegisterMenuId(string menuId)
    {
        if (!_menuIds.Contains(menuId))
        {
            _menuIds.Add(menuId);
            StateHasChanged();
        }
    }

    private void NavigateMenus(int direction)
    {
        if (_menuIds.Count == 0) return;
        if (_openMenuId is null)
        {
            _openMenuId = direction > 0 ? _menuIds[0] : _menuIds[^1];
        }
        else
        {
            var currentIndex = _menuIds.IndexOf(_openMenuId);
            if (currentIndex < 0) return;
            var nextIndex = (currentIndex + direction + _menuIds.Count) % _menuIds.Count;
            _openMenuId = _menuIds[nextIndex];
        }
        StateHasChanged();
    }

    public record MenubarContext(
        string? OpenMenuId,
        EventCallback<string?> SetOpenMenuId,
        bool AnyOpen,
        List<string> MenuIds,
        Action<string> RegisterMenuId,
        Action<int> NavigateMenus);
}

@namespace Lumeo
@implements IAsyncDisposable

@if (Context.OpenMenuId == MenuContext.MenuId)
{
    <div id="@_contentId" role="menu" aria-orientation="vertical" class="@CssClass" @onkeydown="HandleKeyDown" tabindex="-1" @attributes="AdditionalAttributes">
        <CascadingValue Value="_keyNavGuard" IsFixed="true">
            @ChildContent
        </CascadingValue>
    </div>
}

@inject IComponentInteropService Interop

@code {
    [CascadingParameter] public Menubar.MenubarContext Context { get; set; } = default!;
    [CascadingParameter] public MenubarMenu.MenubarMenuContext MenuContext { get; set; } = default!;
    [Parameter] public RenderFragment? ChildContent { get; set; }
    [Parameter] public string? Class { get; set; }
    [Parameter(CaptureUnmatchedValues = true)] public Dictionary<string, object>? AdditionalAttributes { get; set; }

    private readonly string _contentId = LumeoIds.New("menubar-content");
    private readonly MenubarKeyNavGuard _keyNavGuard = new();
    private readonly Lumeo.Services.MenuTypeahead _typeahead = new();
    private bool _registered;
    private int _focusedIndex = -1;

    private string CssClass => Cx.Merge("fixed z-50 min-w-[12rem] overflow-hidden rounded-md border border-border/40 bg-popover p-1 text-popover-foreground shadow-lg animate-fade-in", Class);

    protected override async Task OnAfterRenderAsync(bool firstRender)
    {
        if (Context.OpenMenuId == MenuContext.MenuId && !_registered)
        {
            await Interop.PositionFixed(_contentId, MenuContext.WrapperId, "start");
            // Exclude the menu wrapper (the trigger lives inside it) from the
            // click-outside check. With a null exclusion, mousedown on the open
            // trigger fired this close handler first and the trigger's own click
            // then re-opened the menu — the open trigger could never close it.
            await Interop.RegisterClickOutside(_contentId, MenuContext.WrapperId, async () =>
            {
                await Context.SetOpenMenuId.InvokeAsync(null);
                await InvokeAsync(StateHasChanged);
            });
            _registered = true;
            _focusedIndex = -1;

            // The focused container consumes Arrow/Home/End to move menu focus,
            // but those keys also scroll the page by default — suppress them in
            // JS so keyboard menu navigation doesn't scroll the page behind the
            // open menu (Codex P2). Escape has no scroll default.
            try
            {
                await Interop.RegisterPreventDefaultKeys(_contentId, new[]
                {
                    new Lumeo.Services.PreventDefaultKeyRule("ArrowDown"),
                    new Lumeo.Services.PreventDefaultKeyRule("ArrowUp"),
                    new Lumeo.Services.PreventDefaultKeyRule("ArrowLeft"),
                    new Lumeo.Services.PreventDefaultKeyRule("ArrowRight"),
                    new Lumeo.Services.PreventDefaultKeyRule("Home"),
                    new Lumeo.Services.PreventDefaultKeyRule("End"),
                });
            }
            catch (JSDisconnectedException) { }

            // Move focus to the menu container so Escape/ArrowUp/ArrowDown reach
            // the @onkeydown handler. Without this, focus stays on the trigger
            // button and keyboard nav silently breaks (per WAI-ARIA menu pattern).
            try { await Interop.FocusElement(_contentId); } catch (JSDisconnectedException) { }
        }
        else if (Context.OpenMenuId != MenuContext.MenuId && _registered)
        {
            await Cleanup();
        }
    }

    private async Task HandleKeyDown(KeyboardEventArgs e)
    {
        // An open submenu trigger may already have consumed this key (Blazor
        // cannot stopPropagation for a single key) — see MenubarKeyNavGuard.
        if (_keyNavGuard.Consumed)
        {
            _keyNavGuard.Consumed = false;
            return;
        }

        switch (e.Key)
        {
            case "Escape":
                await Context.SetOpenMenuId.InvokeAsync(null);
                // WCAG 2.4.3: closing the menu from the keyboard returns focus to the
                // trigger that opened it (not done for pointer click-outside, where
                // the user has already moved focus elsewhere — matches Radix). The id
                // mirrors MenubarTrigger's TriggerId.
                try { await Interop.FocusElement($"{MenuContext.WrapperId}-trigger"); }
                catch (JSDisconnectedException) { }
                break;
            case "ArrowLeft":
                // WAI-ARIA menubar: Left/Right inside an open menu close it and
                // open the previous/next menubar menu.
                Context.NavigateMenus(-1);
                break;
            case "ArrowRight":
                Context.NavigateMenus(1);
                break;
            case "ArrowDown":
                {
                    var count = await Interop.GetMenuItemCount(_contentId);
                    if (count > 0)
                    {
                        _focusedIndex = (_focusedIndex + 1) % count;
                        await Interop.FocusMenuItemByIndex(_contentId, _focusedIndex);
                    }
                    break;
                }
            case "ArrowUp":
                {
                    var count = await Interop.GetMenuItemCount(_contentId);
                    if (count > 0)
                    {
                        _focusedIndex = _focusedIndex <= 0 ? count - 1 : _focusedIndex - 1;
                        await Interop.FocusMenuItemByIndex(_contentId, _focusedIndex);
                    }
                    break;
                }
            case "Home":
                {
                    var count = await Interop.GetMenuItemCount(_contentId);
                    if (count > 0)
                    {
                        _focusedIndex = 0;
                        await Interop.FocusMenuItemByIndex(_contentId, _focusedIndex);
                    }
                    break;
                }
            case "End":
                {
                    var count = await Interop.GetMenuItemCount(_contentId);
                    if (count > 0)
                    {
                        _focusedIndex = count - 1;
                        await Interop.FocusMenuItemByIndex(_contentId, _focusedIndex);
                    }
                    break;
                }
            default:
                // Typeahead parity with DropdownMenu (Radix type-to-focus).
                // Printable single chars (not modifier combos) accumulate a query
                // that jumps focus to the first matching item; everything else
                // falls through so Tab/Enter/Space keep native behaviour.
                if (!e.CtrlKey && !e.AltKey && !e.MetaKey && Lumeo.Services.MenuTypeahead.IsTypeaheadKey(e.Key))
                {
                    var query = _typeahead.Push(e.Key);
                    var matched = await Interop.FocusMenuItemByTypeahead(_contentId, query, _focusedIndex);
                    if (matched >= 0) _focusedIndex = matched;
                }
                break;
        }
    }

    private async Task Cleanup()
    {
        try { await Interop.UnpositionFixed(_contentId); } catch (JSDisconnectedException) { }
        try { await Interop.UnregisterClickOutside(_contentId); } catch (JSDisconnectedException) { }
        try { await Interop.UnregisterPreventDefaultKeys(_contentId); } catch (JSDisconnectedException) { }
        _typeahead.Reset();
        _registered = false;
    }

    public async ValueTask DisposeAsync()
    {
        if (_registered) await Cleanup();
    }

    /// <summary>
    /// Cascaded to submenu components so they can mark a navigation key as
    /// handled BEFORE it bubbles up to this menu's @onkeydown. Blazor cannot
    /// conditionally stopPropagation per key, and a blanket stopPropagation on
    /// the submenu trigger would also swallow the Up/Down/Escape keys this
    /// menu must keep handling. Without the guard, ArrowRight on a submenu
    /// trigger would open the submenu AND move the menubar to the next menu,
    /// unmounting the submenu that just opened.
    /// </summary>
    public sealed class MenubarKeyNavGuard
    {
        public bool Consumed { get; set; }
    }
}

